// CSV DOWNLOAD
function downloadCSV(content, filename) {
 try {
 const blob = new Blob(["\uFEFF"+content], {type:"text/csv;charset=utf-8;"});
 const url = URL.createObjectURL(blob);
 const a = document.createElement("a");
 a.href=url; a.setAttribute("download",filename); a.style.display="none";
 document.body.appendChild(a); a.click();
 setTimeout(()=>{ document.body.removeChild(a); URL.revokeObjectURL(url); },100);
 } catch(e) {
 const a = document.createElement("a");
 a.href="data:text/csv;charset=utf-8,"+encodeURIComponent("\uFEFF"+content);
 a.setAttribute("download",filename); a.style.display="none";
 document.body.appendChild(a); a.click(); document.body.removeChild(a);
 }
}

// CSV PARSER
function parseCSV(text) {
 const lines = text.trim().split("\n").map(l=>l.trim()).filter(Boolean);
 if (lines.length < 2) return { headers:[], rows:[] };
 const sep = lines[0].includes(";") ? ";" : ",";
 const headers = lines[0].split(sep).map(h=>h.trim().toLowerCase().replace(/\s+/g,"_"));
 const rows = lines.slice(1).map(line => {
 const vals = line.split(sep).map(v=>v.trim());
 return Object.fromEntries(headers.map((h,i)=>[h, vals[i]??""]));
 });
 return { headers, rows };
}
function validateRows(rows, type) {
 const errors=[];
 const req={ventes_produits:["ca_ht"],charges:["fournisseur","montant_ht"],salaires:["nom_prenom","salaire_brut","salaire_net"],catalogue:["reference","pvht"]};
 const num={ventes_produits:["ca_ht"],charges:["montant_ht"],salaires:["salaire_brut","salaire_net"],catalogue:["pvht"]};
 const r=req[type]||[],n=num[type]||[];
 rows.forEach((row,i)=>{
 r.forEach(f=>{if(!row[f]) errors.push({row:i+1,msg:`Champ manquant : "${f}"`});});
 n.forEach(f=>{if(row[f]&&isNaN(parseFloat(row[f].replace(",",".")))) errors.push({row:i+1,msg:`"${f}" doit être un nombre`});});
 });
 return errors;
}

