function FirstLoginModal({ user, onComplete }) {
  const [newPass, setNewPass]     = useState("");
  const [confirm, setConfirm]     = useState("");
  const [showPass, setShowPass]   = useState(false);
  const [err, setErr]             = useState("");
  const [done, setDone]           = useState(false);

  const rules = [
    { label:"8 caractères minimum",    ok: newPass.length>=8 },
    { label:"Une majuscule",           ok: /[A-Z]/.test(newPass) },
    { label:"Un chiffre",              ok: /[0-9]/.test(newPass) },
    { label:"Les mots de passe correspondent", ok: newPass===confirm&&confirm.length>0 },
  ];
  const valid = rules.every(r=>r.ok);

  const handleSubmit = () => {
    if (!valid) { setErr("Veuillez respecter toutes les règles."); return; }
    // Mettre à jour en mémoire
    const idx = USERS_AUTH.findIndex(u=>u.id===user.id);
    if (idx!==-1) {
      USERS_AUTH[idx] = { ...USERS_AUTH[idx], password:newPass, firstLogin:false };
    }
    setDone(true);
    setTimeout(()=>onComplete({ ...user, firstLogin:false }), 1800);
  };

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,46,44,0.7)",backdropFilter:"blur(4px)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:10000}}>
      <div className="fade-up" style={{background:"white",borderRadius:20,padding:"40px 36px",width:440,boxShadow:"0 32px 80px rgba(0,0,0,0.35)"}}>
        {!done?(
          <>
            <div style={{textAlign:"center",marginBottom:24}}>
              <div style={{width:56,height:56,borderRadius:"50%",background:C.primary,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 16px",fontSize:24,color:"white",fontWeight:900}}>!</div>
              <div style={{fontSize:20,fontWeight:900,color:C.text,marginBottom:8}}>Première connexion</div>
              <div style={{fontSize:13,color:C.textMid,lineHeight:1.7}}>
                Bienvenue <strong>{user.name}</strong> ! Pour sécuriser votre compte, vous devez personnaliser votre mot de passe avant d'accéder à votre espace.
              </div>
            </div>

            <div style={{padding:"12px 16px",background:C.bg,borderRadius:10,marginBottom:20,fontSize:12,color:C.textMid}}>
              Votre mot de passe temporaire vous a été communiqué par votre conseiller NVM Finance par e-mail.
            </div>

            <div style={{marginBottom:14}}>
              <label style={{fontSize:11,fontWeight:800,color:C.textMid,display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.08em"}}>Nouveau mot de passe</label>
              <div style={{position:"relative"}}>
                <input value={newPass} onChange={e=>{setNewPass(e.target.value);setErr("");}} type={showPass?"text":"password"} placeholder="••••••••••" className="inp" style={{paddingRight:40}}/>
                <button onClick={()=>setShowPass(s=>!s)} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:C.textLight,fontSize:14}}>
                  {showPass?"●":"○"}
                </button>
              </div>
            </div>

            <div style={{marginBottom:16}}>
              <label style={{fontSize:11,fontWeight:800,color:C.textMid,display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.08em"}}>Confirmer le mot de passe</label>
              <input value={confirm} onChange={e=>{setConfirm(e.target.value);setErr("");}} type={showPass?"text":"password"} placeholder="••••••••••" className="inp"/>
            </div>

            {/* Règles */}
            <div style={{padding:"12px 14px",background:C.bg,borderRadius:10,marginBottom:16,display:"flex",flexDirection:"column",gap:6}}>
              {rules.map((r,i)=>(
                <div key={i} style={{display:"flex",alignItems:"center",gap:8,fontSize:12}}>
                  <div style={{width:16,height:16,borderRadius:"50%",background:r.ok?C.green:C.borderLight,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                    {r.ok&&<span style={{color:"white",fontSize:10,fontWeight:900}}>✓</span>}
                  </div>
                  <span style={{color:r.ok?C.green:C.textLight,fontWeight:r.ok?700:400}}>{r.label}</span>
                </div>
              ))}
            </div>

            {err&&<div style={{color:C.red,fontSize:12,fontWeight:700,marginBottom:10}}>{err}</div>}

            <Btn variant={valid?"success":"ghost"} disabled={!valid} onClick={handleSubmit} style={{width:"100%",justifyContent:"center",padding:"12px",fontSize:14,borderRadius:9}}>
              Valider et accéder à mon espace
            </Btn>
          </>
        ):(
          <div style={{textAlign:"center",padding:"20px 0"}}>
            <div style={{fontSize:48,marginBottom:16}}>✓</div>
            <div style={{fontSize:20,fontWeight:900,color:C.green,marginBottom:8}}>Mot de passe enregistré</div>
            <div style={{fontSize:13,color:C.textMid}}>Redirection vers votre espace en cours…</div>
          </div>
        )}
      </div>
    </div>
  );
}

