// ADMIN — GESTION CLIENTS (avec bouton Modifier fonctionnel)
function AdminClients({ clients, onViewAsClient, onAddClient, onUpdateClient, onDeleteClient }) {
 const [showAdd,setShowAdd]=useState(false);
 const [newC,setNewC]=useState({name:"",sector:SECTORS[0],manager:"",email:""});
 const [editId,setEditId]=useState(null);
 const [editC,setEditC]=useState({});
 const [confirmDelete,setConfirmDelete]=useState(null); // id du client à supprimer

 const startEdit=(c)=>{ setEditId(c.id); setEditC({name:c.name,sector:c.sector,manager:c.manager,status:c.status}); };
 const saveEdit=()=>{
    const client = clients.find(c=>c.id===editId);
    // Calcul automatique du statut financier
    const kpis = client ? calcMonthKpis(client, moisIdx, moisYear) : null;
    let autoStatus = "healthy";
    if(kpis) {
      const alertes = calcAlertes(client, moisIdx, moisYear);
      const reds = alertes.filter(a=>a.level==="red").length;
      const oranges = alertes.filter(a=>a.level==="orange").length;
      if(reds > 0) autoStatus = "critical";
      else if(oranges > 0) autoStatus = "warning";
      else autoStatus = "healthy";
    }
    onUpdateClient(editId,{name:editC.name,sector:editC.sector,manager:editC.manager,email:editC.email,status:autoStatus});
    setEditId(null);
  };

 const clientToDelete = confirmDelete ? clients.find(c=>c.id===confirmDelete) : null;

 return (
 <div style={{padding:24,display:"flex",flexDirection:"column",gap:20}} className="fade-up">

 {/* Modal confirmation suppression */}
 {confirmDelete&&clientToDelete&&(
   <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:10000}}>
     <div style={{background:"white",borderRadius:16,padding:"32px",width:420,boxShadow:"0 24px 60px rgba(0,0,0,0.3)"}}>
       <div style={{fontSize:18,fontWeight:900,color:C.text,marginBottom:8}}>Supprimer ce dossier ?</div>
       <div style={{fontSize:13,color:C.textMid,marginBottom:20,lineHeight:1.7}}>
         Vous êtes sur le point de supprimer le dossier <strong>{clientToDelete.name}</strong>.<br/>
         Toutes les données (imports, emprunts, investissements) seront perdues.<br/>
         <strong style={{color:C.red}}>Cette action est irréversible.</strong>
       </div>
       <div style={{display:"flex",gap:10}}>
         <Btn variant="ghost" onClick={()=>setConfirmDelete(null)} style={{flex:1,justifyContent:"center"}}>Annuler</Btn>
         <Btn variant="danger" onClick={()=>{onDeleteClient(confirmDelete);setConfirmDelete(null);}} style={{flex:1,justifyContent:"center",background:C.red,borderColor:C.red}}>Supprimer définitivement</Btn>
       </div>
     </div>
   </div>
 )}

 <div style={{display:"flex",justifyContent:"flex-end"}}>
 <Btn variant="success" onClick={()=>setShowAdd(!showAdd)}>+ Nouveau dossier client</Btn>
 </div>
 {showAdd&&(
 <Card style={{border:`2px solid ${C.primary}`}}>
 <SectionHead title="Créer un nouveau dossier client"/>
 <div style={{padding:20,display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
 {[{l:"Raison sociale *",k:"name",ph:"Acme Industries SAS"},{l:"Email accès client",k:"email",ph:"daf@acme.fr"},{l:"Responsable NVM",k:"manager",ph:"Sophie Laurent"}].map(f=>(
 <FormRow key={f.k} label={f.l}><input value={newC[f.k]} onChange={e=>setNewC({...newC,[f.k]:e.target.value})} placeholder={f.ph} className="inp"/></FormRow>
 ))}
 <FormRow label="Secteur"><select value={newC.sector} onChange={e=>setNewC({...newC,sector:e.target.value})} className="inp">{SECTORS.map(s=><option key={s}>{s}</option>)}</select></FormRow>
 </div>
 <div style={{padding:"0 20px 20px",display:"flex",gap:10}}>
 <Btn variant="ghost" onClick={()=>setShowAdd(false)}>Annuler</Btn>
 <Btn variant="success" onClick={()=>{if(newC.name){onAddClient(newC);setNewC({name:"",sector:SECTORS[0],manager:"",email:""});setShowAdd(false);}}}> Créer</Btn>
 </div>
 </Card>
 )}
 {editId&&(
 <Card style={{border:`2px solid ${C.orange}`}}>
 <SectionHead title={`Modifier — ${editC.name}`}/>
 <div style={{padding:20,display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
 <FormRow label="Raison sociale"><input value={editC.name||""} onChange={e=>setEditC({...editC,name:e.target.value})} className="inp"/></FormRow>
 <FormRow label="E-mail client"><input value={editC.email||""} onChange={e=>setEditC({...editC,email:e.target.value})} className="inp" type="email" placeholder="email@client.fr"/></FormRow>
 <FormRow label="Responsable NVM"><input value={editC.manager||""} onChange={e=>setEditC({...editC,manager:e.target.value})} className="inp"/></FormRow>
 <FormRow label="Secteur"><select value={editC.sector||""} onChange={e=>setEditC({...editC,sector:e.target.value})} className="inp">{SECTORS.map(s=><option key={s}>{s}</option>)}</select></FormRow>
 </div>
 <div style={{padding:"0 20px 20px",display:"flex",gap:10}}>
 <Btn variant="ghost" onClick={()=>setEditId(null)}>Annuler</Btn>
 <Btn variant="orange" onClick={saveEdit}> Enregistrer les modifications</Btn>
 </div>
 </Card>
 )}
 <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:16}}>
 {clients.map(c=>(
 <Card key={c.id} style={{overflow:"hidden"}}>
 <div style={{height:4,background:c.color||C.primary}}/>
 <div style={{padding:20}}>
 <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:14}}>
 <div style={{display:"flex",alignItems:"center",gap:12}}>
 <div style={{width:44,height:44,borderRadius:11,background:(c.color||C.primary)+"18",border:`1.5px solid ${(c.color||C.primary)}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,fontWeight:900,color:c.color||C.primary}}>{c.name.slice(0,2).toUpperCase()}</div>
 <div><div style={{fontWeight:800,fontSize:15,color:C.text}}>{c.name}</div><Pill color={C.primary}>{c.sector}</Pill></div>
 </div>
 <span style={{width:9,height:9,borderRadius:"50%",background:c.status==="healthy"?C.green:c.status==="warning"?C.orange:C.red,display:"inline-block",marginTop:4}}/>
 </div>
 <div style={{display:"flex",flexDirection:"column",gap:6,marginBottom:16}}>
 {[["CA mensuel",fmt(c.kpis.ca),C.text],["Résultat",fmt(c.kpis.result),c.kpis.result>=0?C.green:C.red],["Trésorerie",fmt(c.tresorerie?.soldeInitial||c.kpis.tresorerie),(c.tresorerie?.soldeInitial||c.kpis.tresorerie)>=0?C.green:C.red],["Responsable",c.manager,C.textMid]].map(([l,v,col])=>(
 <div key={l} style={{display:"flex",justifyContent:"space-between",fontSize:12}}><span style={{color:C.textLight}}>{l}</span><strong style={{color:col}}>{v}</strong></div>
 ))}
 </div>
 {c.alertes?.length>0&&<div style={{marginBottom:12}}><Pill color={C.orange}>{c.alertes.length} alerte{c.alertes.length>1?"s":""}</Pill></div>}
 <div style={{display:"flex",gap:8}}>
 <Btn small variant="ghost" style={{flex:1,justifyContent:"center"}} onClick={()=>startEdit(c)}>Modifier</Btn>
 <Btn small variant="primary" style={{flex:2,justifyContent:"center"}} onClick={()=>onViewAsClient(c)}>Voir comme client</Btn>
 </div>
 <div style={{marginTop:6}}>
 <Btn small variant="ghost" style={{width:"100%",justifyContent:"center",color:C.red,borderColor:C.red+"44",fontSize:11}} onClick={()=>setConfirmDelete(c.id)}>Supprimer ce dossier</Btn>
 </div>
 </div>
 </Card>
 ))}
 </div>
 </div>
 );
}

// ADMIN — SAISIE CSV
function AdminSaisie({ clients, onUpdateClient }) {
 const [selId,setSelId]=useState(clients[0]?.id||"");
 const [mod,setMod]=useState("ventes_produits");
 const [moisImport,setMoisImport]=useState("2025-10");
 const [csvPreview,setCsvPreview]=useState(null);
 const [importMsg,setImportMsg]=useState("");
 const client=clients.find(c=>c.id===Number(selId));

 const CSV_MODULES=[
 {id:"ventes_produits",label:"Ventes produits"},
 {id:"autres_ventes",label:"Autres ventes"},
 {id:"charges",label:"Charges"},
 {id:"salaires",label:"Masse salariale"},
 {id:"catalogue",label:"Catalogue produits"},
 {id:"creances_clients",label:"Creances clients"},
 {id:"dettes_fournisseurs",label:"Dettes fournisseurs"},
 ];
 const HINTS={
 ventes_produits:"Ventes par produit / service selon le secteur",
 autres_ventes:"Subventions, cessions, prestations accessoires",
 charges:"Charges fixes et variables avec TVA recuperable",
 salaires:"Cout total employeur — salaires bruts, cotisations, net",
 catalogue:"Tarifs, marges et references produits",
 creances_clients:"Factures emises non encore encaissees — suivi delais paiement client",
 dettes_fournisseurs:"Factures recues non encore payees — suivi echeances fournisseurs",
 };


 const handleFileChange=(e)=>{
 const file=e.target.files?.[0]; if(!file) return;
 const reader=new FileReader();
 reader.onload=(ev)=>{
 const {headers,rows}=parseCSV(ev.target.result);
 const errors=validateRows(rows,mod);
 setCsvPreview({file,headers,rows,errors,mois:moisImport});
 };
 reader.readAsText(file,"utf-8");
 e.target.value="";
 };

 const handleConfirm=async(rows,mois)=>{
 const label=CSV_MODULES.find(m=>m.id===mod)?.label||mod;
 const existing=(client.imports||[]);
 const importedAt=new Date().toLocaleDateString("fr-FR");
 const newImport={id:Date.now(),type:mod,label,mois,rows,count:rows.length,importedAt};
 onUpdateClient(client.id,{imports:[...existing,newImport]});
 setCsvPreview(null);
 setImportMsg(` ${rows.length} ligne${rows.length>1?"s":""} importée${rows.length>1?"s":""} dans "${label}" — ${mois}`);
 setTimeout(()=>setImportMsg(""),5000);
 try {
   await supabase.from("imports_csv").upsert({
     client_id:client.id,type:mod,label,mois,
     rows,count:rows.length,imported_at:importedAt,
   },{onConflict:"client_id,type,mois"});
 } catch(e){console.error("Erreur sauvegarde import:",e);}
 };

 const handleDownload=()=>{
 const sector=client?.sector||"default";
 const tmpl=getTemplate(mod,sector);
 if(!tmpl){setImportMsg("Template non disponible.");setTimeout(()=>setImportMsg(""),3000);return;}
 const slug=sector.replace(/[^a-zA-Z0-9]/g,"_").toLowerCase();
 downloadCSV(tmpl,`nvm_template_${mod}_${slug}.csv`);
 setImportMsg(` Template téléchargé (${sector})`);
 setTimeout(()=>setImportMsg(""),4000);
 };


 return (
 <div style={{padding:24,display:"flex",flexDirection:"column",gap:20}} className="fade-up">
 {csvPreview&&<CSVPreviewModal file={csvPreview.file} rows={csvPreview.rows} headers={csvPreview.headers} errors={csvPreview.errors} mois={csvPreview.mois} onConfirm={handleConfirm} onCancel={()=>setCsvPreview(null)}/>}

 {/* Client */}
 <Card>
 <div style={{padding:"14px 18px",display:"flex",alignItems:"center",gap:16,flexWrap:"wrap"}}>
 <span style={{fontSize:13,fontWeight:800,color:C.textMid}}>Client :</span>
 <select value={selId} onChange={e=>setSelId(e.target.value)} className="inp" style={{width:"auto"}}>
 {clients.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
 </select>
 {client&&<><Pill color={C.primary}>{client.sector}</Pill></>}
 </div>
 </Card>

 {/* Modules */}
 <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
 {CSV_MODULES.map(m=>(
 <button key={m.id} onClick={()=>setMod(m.id)}
 style={{padding:"7px 14px",borderRadius:7,border:`1.5px solid ${mod===m.id?C.primary:C.border}`,background:mod===m.id?C.primary:"white",color:mod===m.id?"white":C.textMid,fontSize:12,fontWeight:800,cursor:"pointer",transition:"all .15s"}}>
 {m.label}
 </button>
 ))}
 </div>

 <Card>
 <SectionHead
 title={`${CSV_MODULES.find(m=>m.id===mod)?.label} — Import CSV`}
 sub={HINTS[mod]}
 action={
 <div style={{display:"flex",gap:8,alignItems:"center"}}>
 {importMsg&&<span style={{fontSize:12,color:importMsg.startsWith("")?C.red:C.green,fontWeight:800}}>{importMsg}</span>}
 <Btn small variant="ghost" onClick={handleDownload}> Télécharger template</Btn>
 </div>
 }
 />

 <div style={{padding:20,display:"flex",flexDirection:"column",gap:14}}>

 {/* Mois */}
 <div style={{display:"flex",alignItems:"center",gap:14,padding:"12px 16px",background:C.bg,borderRadius:10,border:`1.5px solid ${C.border}`,flexWrap:"wrap"}}>
 <span style={{fontSize:13,fontWeight:800,color:C.text}}> Mois de rattachement :</span>
 <input type="month" value={moisImport} onChange={e=>setMoisImport(e.target.value)}
 style={{padding:"7px 12px",border:`1.5px solid ${C.border}`,borderRadius:7,fontSize:14,fontWeight:700,color:C.text,fontFamily:"inherit",background:"white"}}/>
 <span style={{fontSize:12,color:C.textLight}}>Toutes les lignes importées seront rattachées à ce mois</span>
 </div>

 {/* Zone d'import fichier — input visible stylisé */}
 <div style={{border:`2px dashed ${C.border}`,borderRadius:12,padding:"32px 20px",textAlign:"center",background:C.bg}}>
 <div style={{fontSize:32,marginBottom:10}}></div>
 <div style={{fontSize:14,fontWeight:800,color:C.text,marginBottom:6}}>Sélectionnez votre fichier CSV</div>
 <div style={{fontSize:12,color:C.textLight,marginBottom:18}}>Le mois sélectionné ci-dessus sera rattaché aux données</div>
 <input
 type="file"
 accept=".csv,.txt"
 onChange={handleFileChange}
 style={{
 display:"block",
 margin:"0 auto",
 padding:"10px 20px",
 background:C.primary,
 color:"white",
 border:"none",
 borderRadius:8,
 fontSize:13,
 fontWeight:800,
 fontFamily:"inherit",
 cursor:"pointer",
 width:"auto",
 }}
 />
 <div style={{marginTop:12,fontSize:11,color:C.textLight}}>Formats acceptés : .csv · Séparateur ; ou ,</div>
 </div>
 </div>

 {/* Historique */}
 {(client?.imports||[]).filter(imp=>imp.type===mod).length>0&&(
 <div style={{borderTop:`1px solid ${C.borderLight}`,padding:16}}>
 <div style={{fontSize:12,fontWeight:800,color:C.textMid,marginBottom:10}}>
 Imports enregistrés — {CSV_MODULES.find(m=>m.id===mod)?.label}
 </div>
 {(client.imports||[]).filter(imp=>imp.type===mod).map(imp=>(
 <div key={imp.id} style={{display:"flex",alignItems:"center",gap:12,padding:"8px 12px",background:C.bg,borderRadius:8,marginBottom:6}}>
 <Pill color={C.green}>{imp.mois}</Pill>
 <span style={{fontSize:12,fontWeight:700,color:C.text}}>{imp.count} ligne{imp.count>1?"s":""}</span>
 <span style={{fontSize:11,color:C.textLight}}>le {imp.importedAt}</span>
 </div>
 ))}
 </div>
 )}
 </Card>
 </div>
 );
}


// ADMIN — DONNÉES FINANCIÈRES
