 const ajM=(client.tresorerie?.ajustements||[]).filter(a=>a.mois===`${moisYear}-${String(i+1).padStart(2,"0")}`);
 const ajE=ajM.filter(a=>a.type==="encaissement").reduce((s,a)=>s+a.montant,0);
