// ALERTES VIEW
// ════════════════════════════════════════════════════════
function AlertesView({ clients, singleClient, moisIdx, moisYear }) {
  const curM = moisIdx !== undefined ? moisIdx : CUR_M;
  const curY = moisYear !== undefined ? moisYear : CUR_Y;
  const allAlerts = singleClient
    ? calcAlertes(singleClient, curM, curY).map(a=>({...a, clientName:singleClient.name}))
    : (clients||[]).flatMap(c=> calcAlertes(c, curM, curY).map(a=>({...a, clientName:c.name})));
  const critiques = allAlerts.filter(a=>a.level==="red");
  const attention = allAlerts.filter(a=>a.level==="orange");
  const ok = allAlerts.filter(a=>a.level==="green");
  return (
    <div style={{padding:singleClient?0:24}} className="fade-up">
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:14,marginBottom:20}}>
        <KpiCard label="Critiques" value={critiques.length} sub={critiques.length>0?"Action requise":"Aucune"} color={C.red}/>
        <KpiCard label="Vigilance" value={attention.length} sub={attention.length>0?"A surveiller":"Aucune"} color={C.orange}/>
        <KpiCard label="Points sains" value={ok.length} sub="Tout va bien" color={C.green}/>
      </div>
      {critiques.map((a,i)=>(
        <div key={i} style={{background:C.white,border:`2px solid ${C.red}44`,borderLeft:`5px solid ${C.red}`,borderRadius:10,padding:"16px 20px",marginBottom:12,display:"flex",gap:14,alignItems:"flex-start"}}>
          <div style={{flex:1}}>
            <div style={{display:"flex",gap:10,marginBottom:8,alignItems:"center",flexWrap:"wrap"}}>
              <Pill color={C.red} bg={C.redBg}>CRITIQUE</Pill>
              {!singleClient&&<Pill color={C.primary}>{a.clientName}</Pill>}
              <strong style={{fontSize:14,color:C.text}}>{a.kpi}</strong>
            </div>
            <div style={{fontSize:13,color:C.textMid,marginBottom:8,lineHeight:1.6}}>{a.msg}</div>
            {a.threshold&&<div style={{display:"flex",gap:16,fontSize:12,marginBottom:8}}>
              <span style={{color:C.textLight}}>Valeur : <strong style={{color:C.red}}>{a.current}</strong></span>
              <span style={{color:C.textLight}}>Objectif : <strong>{a.threshold}</strong></span>
            </div>}
            {a.action&&<div style={{padding:"8px 14px",background:C.redBg,borderRadius:8,fontSize:12,color:C.red,fontWeight:700}}>{a.action}</div>}
          </div>
        </div>
      ))}
      {attention.map((a,i)=>(
        <div key={i} style={{background:C.white,border:`1.5px solid ${C.orange}44`,borderLeft:`5px solid ${C.orange}`,borderRadius:10,padding:"16px 20px",marginBottom:12,display:"flex",gap:14,alignItems:"flex-start"}}>
          <div style={{flex:1}}>
            <div style={{display:"flex",gap:10,marginBottom:8,alignItems:"center",flexWrap:"wrap"}}>
              <Pill color={C.orange} bg={C.orangeBg}>VIGILANCE</Pill>
              {!singleClient&&<Pill color={C.primary}>{a.clientName}</Pill>}
              <strong style={{fontSize:14,color:C.text}}>{a.kpi}</strong>
            </div>
            <div style={{fontSize:13,color:C.textMid,marginBottom:8,lineHeight:1.6}}>{a.msg}</div>
            {a.threshold&&<div style={{display:"flex",gap:16,fontSize:12,marginBottom:8}}>
              <span style={{color:C.textLight}}>Valeur : <strong style={{color:C.orange}}>{a.current}</strong></span>
              <span style={{color:C.textLight}}>Objectif : <strong>{a.threshold}</strong></span>
            </div>}
            {a.action&&<div style={{padding:"8px 14px",background:C.orangeBg,borderRadius:8,fontSize:12,color:C.orange,fontWeight:700}}>{a.action}</div>}
          </div>
        </div>
      ))}
      {ok.map((a,i)=>(
        <div key={i} style={{background:C.greenBg,border:`1px solid ${C.green}33`,borderLeft:`4px solid ${C.green}`,borderRadius:10,padding:"14px 20px",marginBottom:10,display:"flex",gap:12,alignItems:"center"}}>
          <div>
            <div style={{fontWeight:800,fontSize:13,color:C.green}}>{a.kpi}</div>
            <div style={{fontSize:12,color:C.textMid,marginTop:2}}>{a.msg}</div>
          </div>
        </div>
      ))}
    </div>
  );
}

