function AdminAcces({ clients }) {
  const [resetDone, setResetDone] = useState({});
  const [newPassVisible, setNewPassVisible] = useState({});

  const handleReset = (email) => {
    const idx = USERS_AUTH.findIndex(u=>u.email===email);
    if (idx===-1) return;
    const newPass = generateTempPassword();
    USERS_AUTH[idx] = { ...USERS_AUTH[idx], password:newPass, firstLogin:true };
    // Marquer la demande comme traitée
    const req = RESET_REQUESTS.find(r=>r.email===email);
    if (req) req.status = "done";
    setResetDone(prev=>({...prev, [email]:newPass}));
  };

  const clientUsers = USERS_AUTH.filter(u=>u.role==="CLIENT");
  const pendingRequests = RESET_REQUESTS.filter(r=>r.status==="pending");

  return (
    <div style={{padding:24,display:"flex",flexDirection:"column",gap:20}} className="fade-up">

      {/* Demandes en attente */}
      <Card>
        <SectionHead
          title="Demandes de réinitialisation"
          sub={pendingRequests.length>0?`${pendingRequests.length} demande${pendingRequests.length>1?"s":""} en attente`:"Aucune demande en attente"}
        />
        {pendingRequests.length===0?(
          <div style={{padding:"32px 0",textAlign:"center",color:C.textLight}}>
            <div style={{fontSize:32,marginBottom:10}}>✓</div>
            <div style={{fontSize:14,fontWeight:700}}>Aucune demande de réinitialisation</div>
            <div style={{fontSize:12,marginTop:6}}>Les demandes de vos clients apparaîtront ici</div>
          </div>
        ):(
          <div style={{padding:0}}>
            {pendingRequests.map(req=>(
              <div key={req.id} style={{padding:"16px 20px",borderBottom:`1px solid ${C.borderLight}`,display:"flex",alignItems:"center",gap:16}}>
                <div style={{flex:1}}>
                  <div style={{fontWeight:800,fontSize:14,color:C.text,marginBottom:2}}>{req.name}</div>
                  <div style={{fontSize:12,color:C.textMid}}>{req.email} · Demande le {req.date}</div>
                </div>
                {resetDone[req.email]?(
                  <div style={{textAlign:"right"}}>
                    <Pill color={C.green}>Traité</Pill>
                    <div style={{fontSize:11,color:C.textMid,marginTop:4}}>Nouveau MP : <strong style={{fontFamily:"'Courier New',monospace",color:C.primary}}>{resetDone[req.email]}</strong></div>
                    <div style={{fontSize:10,color:C.orange,marginTop:2}}>À communiquer au client</div>
                  </div>
                ):(
                  <Btn variant="orange" small onClick={()=>handleReset(req.email)}>
                    Générer un nouveau mot de passe
                  </Btn>
                )}
              </div>
            ))}
          </div>
        )}
      </Card>

      {/* Tous les comptes clients */}
      <Card>
        <SectionHead title="Comptes clients actifs" sub="Gérez les accès et réinitialisez les mots de passe"/>
        <table style={{width:"100%",borderCollapse:"collapse"}}>
          <thead>
            <tr>
              <Th>Client</Th>
              <Th>E-mail</Th>
              <Th>Statut</Th>
              <Th>Mot de passe temporaire</Th>
              <Th right>Actions</Th>
            </tr>
          </thead>
          <tbody>
            {clientUsers.map((u,i)=>{
              const client = clients.find(c=>c.id===u.clientId);
              const newPass = resetDone[u.email];
              const isFirstLogin = u.firstLogin;
              return (
                <Tr key={i}>
                  <Td bold>{client?.name||u.name}</Td>
                  <Td color={C.textMid}>{u.email}</Td>
                  <Td>
                    {isFirstLogin
                      ? <Pill color={C.orange}>1ère connexion en attente</Pill>
                      : <Pill color={C.green}>Actif</Pill>
                    }
                  </Td>
                  <Td>
                    {newPass?(
                      <div style={{display:"flex",alignItems:"center",gap:8}}>
                        <span style={{fontFamily:"'Courier New',monospace",fontWeight:800,color:C.primary,fontSize:13}}>{newPass}</span>
                        <Pill color={C.orange}>À communiquer</Pill>
                      </div>
                    ):(<span style={{color:C.textLight,fontSize:12}}>—</span>)}
                  </Td>
                  <Td right>
                    <Btn small variant={newPass?"ghost":"primary"} onClick={()=>handleReset(u.email)}>
                      {newPass?"Régénérer":"Réinitialiser MP"}
                    </Btn>
                  </Td>
                </Tr>
              );
            })}
            {clientUsers.length===0&&(
              <Tr><Td colspan="5" style={{textAlign:"center",padding:"32px",color:C.textLight}}>Aucun compte client créé</Td></Tr>
            )}
          </tbody>
        </table>
        <div style={{padding:"12px 16px",background:"#fffbeb",borderTop:`1px solid ${C.border}`,fontSize:12,color:C.textMid}}>
          Après réinitialisation, le nouveau mot de passe temporaire s'affiche ici. Communiquez-le au client — il devra le changer à sa prochaine connexion.
        </div>
      </Card>
    </div>
  );
}

function RapportIA({ clients, moisIdx, moisYear }) {
  const [selId,setSelId]=useState(clients[0]?.id);
  const [text,setText]=useState("");
  const [loading,setLoading]=useState(false);
  const client=clients.find(c=>c.id===selId);
  const kpis=client?calcMonthKpis(client,moisIdx,moisYear):null;

  const generate=async()=>{
    if(!client||!kpis) return;
    setLoading(true); setText("");
    const prompt=`Tu es analyste financier senior chez NVM Finance. Rapport mensuel pour :\nClient : ${client.name} | Secteur : ${client.sector} | Periode : ${MONTHS[moisIdx]} ${moisYear}\nCA HT : ${fmt(kpis.ca)} | Marge brute : ${fmt(kpis.marge)} (${pct(kpis.ca>0?kpis.marge/kpis.ca*100:0)}) | EBE : ${fmt(kpis.ebe)} | Resultat : ${fmt(kpis.result)}\nEmprunts : ${(client.emprunts||[]).length} en cours | Investissements : ${(client.investissements||[]).length}\nAlertes : ${calcAlertes(client,moisIdx,moisYear).filter(a=>a.level!=="green").map(a=>`[${a.level.toUpperCase()}] ${a.kpi}`).join(", ")||"Aucune"}\nRedige : 1. SYNTHESE 2. PERFORMANCES 3. TRESORERIE 4. POINTS D'ATTENTION 5. 3 RECOMMANDATIONS — Professionnel, concis, oriente decision.`;
    try {
      const res=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:prompt}]})});
      const data=await res.json();
      setText(data.content?.map(b=>b.text||"").join("")||"Erreur.");
    } catch { setText("Erreur reseau."); }
    setLoading(false);
  };

  const renderMD=(t)=>t.split("\n").map((line,i)=>{
    if(/^\*\*\d+\./.test(line)||(/^\*\*/.test(line)&&line.endsWith("**"))) return <div key={i} style={{fontWeight:800,color:C.primary,fontSize:14,marginTop:18,marginBottom:4,paddingBottom:4,borderBottom:`2px solid ${C.bg}`}}>{line.replace(/\*\*/g,"")}</div>;
    if(line.startsWith("- ")) return <div key={i} style={{paddingLeft:14,color:C.textMid,fontSize:13,lineHeight:1.7,position:"relative"}}><span style={{position:"absolute",left:2,color:C.green}}>›</span>{line.slice(2).replace(/\*\*/g,"")}</div>;
    if(!line.trim()) return <div key={i} style={{height:8}}/>;
    return <div key={i} style={{color:C.textMid,fontSize:13,lineHeight:1.8}}>{line.replace(/\*\*/g,"")}</div>;
  });

  return (
    <div style={{padding:24}} className="fade-up">
      <Card>
        <SectionHead title="Generation de rapport IA" sub="Rapport de gestion mensuel genere par Claude"/>
        <div style={{padding:16,display:"flex",gap:12,alignItems:"center",flexWrap:"wrap"}}>
          <select value={selId} onChange={e=>setSelId(Number(e.target.value))} className="inp" style={{width:"auto"}}>{clients.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}</select>
          <span style={{fontSize:13,color:C.textMid,fontWeight:700}}>{MONTHS[moisIdx]} {moisYear}</span>
          <Btn onClick={generate} disabled={loading} variant="success">{loading?"Generation...":"Generer rapport IA"}</Btn>
        </div>
        {loading&&<div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:12,padding:"40px 0"}}><div style={{width:32,height:32,border:`3px solid ${C.border}`,borderTop:`3px solid ${C.primary}`,borderRadius:"50%",animation:"spin 1s linear infinite"}}/><span style={{color:C.textLight}}>Analyse en cours...</span></div>}
        {text&&!loading&&<div style={{margin:"0 16px 16px",padding:"24px 28px",background:C.bg,borderRadius:10,border:`1px solid ${C.border}`}}><div style={{fontSize:14,fontWeight:800,color:C.text,marginBottom:18,paddingBottom:14,borderBottom:`2px solid ${C.borderLight}`}}>Rapport de gestion — {MONTHS[moisIdx]} {moisYear} — {client?.name}</div>{renderMD(text)}</div>}
        {!text&&!loading&&<div style={{textAlign:"center",padding:"60px 0",color:C.textLight}}><div style={{fontSize:15,fontWeight:700,marginBottom:8}}>Selectionnez un client et generez le rapport</div></div>}
      </Card>
    </div>
  );
}

export default function App() {
  const [user,setUser]=useState(null);
  const [view,setView]=useState("clients");
  const [resetMode,setResetMode]=useState(false);
  const [resetPassword,setResetPassword]=useState("");
  const [resetConfirm,setResetConfirm]=useState("");
  const [resetMsg,setResetMsg]=useState("");

  // Détecter si on arrive avec un token de reset/invite dans l'URL
  useEffect(()=>{
    const hash = window.location.hash;
    const params = new URLSearchParams(hash.replace("#",""));
    const type = params.get("type");
    const accessToken = params.get("access_token");
    if((type==="recovery" || type==="invite") && accessToken) {
      // Établir la session avec le token
      supabase.auth.setSession({
        access_token: accessToken,
        refresh_token: params.get("refresh_token")||""
      }).then(({error})=>{
        if(!error) {
          setResetMode(true);
          window.history.replaceState(null,"","/");
        }
      });
    }
  },[]);

  // resetMode sera géré dans le return principal
  // ── Clients : démos fixes + clients créés persistés dans storage ──
  const [clients,setClients]=useState([]);

  useEffect(()=>{
    (async()=>{
      try {
        const {data:cd,error:ce}=await supabase.from("clients").select("*").order("id");
        if(ce) throw ce;
        const {data:id2}=await supabase.from("imports_csv").select("*");
        const {data:ud}=await supabase.from("client_users").select("*");
        if(!cd||cd.length===0) return;
        const extras=cd.map(c=>({
          id:c.id,name:c.name,sector:c.sector,color:c.color,manager:c.manager,
          since:c.since,status:c.status,email:c.email||"",
          kpis:c.kpis||{ca:0,marge:0,charges:0,salaires:0,ebe:0,result:0,tresorerie:0},
          emprunts:c.emprunts||[],investissements:c.investissements||[],
          tresorerie:c.tresorerie||{soldeInitial:0,ajustements:[]},
          is:c.is_data||{totalPrecedent:0,taux:15},
          previsionnel:c.previsionnel||{adjustments:{}},
          imports:(id2||[]).filter(i=>i.client_id===c.id).map(i=>({
            id:i.id,type:i.type,label:i.label,mois:i.mois,
            rows:i.rows||[],count:i.count,importedAt:i.imported_at,
          })),
        }));
        (ud||[]).forEach(u=>{
          if(!USERS_AUTH.find(a=>a.email===u.email)){
            USERS_AUTH.push({id:"c"+u.client_id,email:u.email,password:u.password,
              role:"CLIENT",clientId:u.client_id,
              name:extras.find(c=>c.id===u.client_id)?.name||"",firstLogin:u.first_login});
          }
        });
        setClients(extras);
      } catch(e){console.error("Supabase load error:",e);}
    })();
  },[]);

  const saveClientToSupabase=async(client)=>{
    try {
      await supabase.from("clients").upsert({
        id:client.id,name:client.name,sector:client.sector||"",color:client.color,
        manager:client.manager,since:client.since,status:client.status,email:client.email||"",
        kpis:client.kpis,emprunts:client.emprunts||[],investissements:client.investissements||[],
        tresorerie:client.tresorerie||{soldeInitial:0,ajustements:[]},
        is_data:client.is||{totalPrecedent:0,taux:15},
        previsionnel:client.previsionnel||{adjustments:{}},
      },{onConflict:"id"});
    } catch(e){console.error("Supabase save error:",e);}
  };
  const [previewClient,setPreviewClient]=useState(null);
  const [moisCourant,setMoisCourant]=useState(`${CUR_Y}-${String(CUR_M+1).padStart(2,"0")}`);
  const moisYear=parseInt(moisCourant.split("-")[0]);
  const moisIdx=parseInt(moisCourant.split("-")[1])-1;
  const setMoisIdx=(fn)=>{
    setMoisCourant(prev=>{
      const [y,m]=prev.split("-").map(Number);
      const curM=m-1;
      const newM=typeof fn==="function"?fn(curM):fn;
      let nm=newM,ny=y;
      if(nm<0){nm=11;ny--;}
      if(nm>11){nm=0;ny++;}
      if(ny>CUR_Y||(ny===CUR_Y&&nm>CUR_M)) return prev;
      return `${ny}-${String(nm+1).padStart(2,"0")}`;
    });
  };

  const totalAlerts=clients.reduce((s,c)=>s+calcAlertes(c,moisIdx,moisYear).filter(a=>a.level==="red"||a.level==="orange").length,0);
  const updateClient=useCallback(async(id,patch)=>{
    setClients(prev=>prev.map(c=>c.id===id?{...c,...patch}:c));
    setPreviewClient(prev=>prev?.id===id?{...prev,...patch}:prev);
    // Sauvegarder dans Supabase
    try {
      const client = (await supabase.from("clients").select("*").eq("id",id).single()).data;
      if(!client) return;
      const updated = {...client,...patch};
      // Sauvegarder les champs clients
      await supabase.from("clients").upsert({
        id,name:updated.name,sector:updated.sector||"",color:updated.color,
        manager:updated.manager,since:updated.since,status:updated.status,email:updated.email||"",
        kpis:updated.kpis||{},emprunts:updated.emprunts||[],
        investissements:updated.investissements||[],
        tresorerie:updated.tresorerie||{soldeInitial:0,ajustements:[]},
        is_data:updated.is||{totalPrecedent:0,taux:15},
        previsionnel:updated.previsionnel||{adjustments:{}},
      },{onConflict:"id"});
      // Si patch contient des imports, les sauvegarder séparément
      if(patch.imports) {
        const newImports = patch.imports.filter(i=>!i.id||i.id>999999999);
        for(const imp of newImports) {
          await supabase.from("imports_csv").upsert({
            client_id:id,type:imp.type,label:imp.label,mois:imp.mois,
            rows:imp.rows,count:imp.count,imported_at:imp.importedAt,
          },{onConflict:"client_id,type,mois"});
        }
      }
    } catch(e){console.error("Supabase updateClient error:",e);}
  },[]);
  const handleLogin=(u)=>{
    // Relire depuis USERS_AUTH pour avoir firstLogin à jour
    const fresh = USERS_AUTH.find(x=>x.id===u.id)||u;
    setUser(fresh);
    setView(fresh.role==="ADMIN"?"clients":"dashboard");
  };
  const handleLogout=()=>{setUser(null);setView("clients");setPreviewClient(null);};
  const [newClientCredentials, setNewClientCredentials] = useState(null);

  const handleAddClient=async(newC)=>{
    const newClient = {name:newC.name,sector:newC.sector||"",color:C.primaryLight,manager:newC.manager||"A definir",since:String(new Date().getFullYear()),status:"healthy",kpis:{ca:0,marge:0,charges:0,salaires:0,ebe:0,result:0,tresorerie:0},emprunts:[],investissements:[],tresorerie:{soldeInitial:0,ajustements:[]},is:{totalPrecedent:0,taux:15},imports:[],previsionnel:{adjustments:{}}};
    try {
      // 1. Créer le client dans Supabase
      const {data,error}=await supabase.from("clients").insert({
        name:newClient.name,sector:newClient.sector,color:newClient.color,
        manager:newClient.manager,since:newClient.since,status:newClient.status,
        email:newC.email||"",kpis:newClient.kpis,emprunts:[],investissements:[],
        tresorerie:newClient.tresorerie,is_data:newClient.is,previsionnel:newClient.previsionnel,
      }).select().single();
      if(error) throw error;
      const clientAvecId={...newClient,id:data.id};
      setClients(prev=>[...prev,clientAvecId]);
      // 2. Inviter le client par email via Supabase Auth
      if(newC.email){
        const res = await fetch("/api/invite",{
          method:"POST",
          headers:{"Content-Type":"application/json"},
          body:JSON.stringify({email:newC.email,clientId:data.id,name:newC.name}),
        });
        const inv = await res.json();
        if(inv.error){
          console.error("Erreur invitation:",inv.error);
          // Fallback : mot de passe temporaire
          const tempPass = generateTempPassword();
          await supabase.from("client_users").insert({client_id:data.id,email:newC.email,password:tempPass,first_login:true});
          USERS_AUTH.push({id:"c"+data.id,email:newC.email,password:tempPass,role:"CLIENT",clientId:data.id,name:newC.name,firstLogin:true});
          setNewClientCredentials({name:newC.name,email:newC.email,tempPass,invited:false});
        } else {
          // Invitation réussie → ajouter dans client_users
          await supabase.from("client_users").upsert({
            client_id:data.id, email:newC.email, password:"", first_login:false
          },{onConflict:"email"});
          setNewClientCredentials({name:newC.name,email:newC.email,tempPass:null,invited:true});
        }
      } else {
        setNewClientCredentials({name:newC.name,email:"(email non renseigné)",tempPass:null,invited:false});
      }
    } catch(e){
      console.error("Erreur création client:",e);
      alert("Erreur: "+e.message);
    }
  };

  const ADMIN_TITLES={clients:`Portefeuille clients (${clients.length})`,acces:"Accès & mots de passe clients",saisie:"Saisie & Import CSV",financier:"Donnees financieres",alertes:"Centre d'alertes",rapports:"Rapports IA"};
  const CLIENT_TITLES={dashboard:"Tableau de bord",alertes:"Mes alertes",ventes:"Mes ventes",achats:"Mes couts d'achat",charges:"Mes charges",salaires:"Ma masse salariale",creances:"Mes créances clients",dettes:"Mes dettes fournisseurs",resultat:"Mon resultat financier",tresorerie:"Ma tresorerie",emprunts:"Mes emprunts",investissements:"Mes investissements",is:"Mon impot (IS)",catalogue:"Mon catalogue produits", comparaison:"Comparaison de périodes", previsionnel:"Prévisionnel hybride 2026"};

  // Modal credentials nouveau client (admin)
  const CredentialsModal = newClientCredentials ? (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:10000}}>
      <div className="fade-up" style={{background:"white",borderRadius:16,padding:"36px 32px",width:420,boxShadow:"0 24px 60px rgba(0,0,0,0.3)"}}>
        <div style={{fontSize:18,fontWeight:900,color:C.text,marginBottom:6}}>Dossier client créé</div>
        <div style={{fontSize:13,color:C.textMid,marginBottom:20,lineHeight:1.6}}>
          Le compte a été créé. Un e-mail d'invitation a été envoyé automatiquement à votre client.
        </div>
        <div style={{background:C.bg,borderRadius:10,padding:16,marginBottom:20,display:"flex",flexDirection:"column",gap:10}}>
          <div style={{fontSize:12,color:C.textMid}}>Client : <strong style={{color:C.text}}>{newClientCredentials.name}</strong></div>
          <div style={{fontSize:12,color:C.textMid}}>E-mail : <strong style={{color:C.primary}}>{newClientCredentials.email}</strong></div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 14px",background:"white",borderRadius:8,border:`1px solid ${C.border}`}}>
            <div>
              <div style={{fontSize:10,color:C.textLight,marginBottom:3,textTransform:"uppercase",fontWeight:800}}>Mot de passe temporaire</div>
              <div style={{fontSize:18,fontWeight:900,color:C.primary,letterSpacing:"0.1em",fontFamily:"'Courier New',monospace"}}>{newClientCredentials.tempPass}</div>
            </div>
          </div>
          <div style={{fontSize:11,color:C.orange,fontWeight:700}}>Le client devra changer ce mot de passe lors de sa première connexion.</div>
        </div>
        <Btn variant="success" onClick={()=>setNewClientCredentials(null)} style={{width:"100%",justifyContent:"center"}}>Compris, fermer</Btn>
      </div>
    </div>
  ) : null;

  // Popup première connexion client
  const FirstLoginPopup = (user && user.firstLogin) ? (
    <FirstLoginModal user={user} onComplete={(updatedUser)=>setUser(updatedUser)}/>
  ) : null;

  if (previewClient) {
    const live=clients.find(c=>c.id===previewClient.id)||previewClient;
    return (
      <div style={{display:"flex",height:"100vh",fontFamily:"'Nunito',sans-serif"}}>
        <GlobalCSS/>
        <ClientSidebar view={view} setView={setView} onLogout={()=>setPreviewClient(null)} clientName={live.name} alertCount={calcAlertes(live,moisIdx,moisYear).filter(a=>a.level==="red"||a.level==="orange").length}/>
        <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
          <TopBar
            title={`Apercu client — ${live.name}`}
            user={{name:"Admin",role:"ADMIN"}}
            extra={
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <span style={{fontSize:12,color:C.textMid,fontWeight:700}}>Mode apercu</span>
                <Btn small variant="primary" onClick={()=>setPreviewClient(null)}>← Retour admin</Btn>
              </div>
            }
          />
          <div style={{flex:1,overflowY:"auto"}}>
            <ClientSpace client={live} view={view} moisIdx={moisIdx} setMoisIdx={setMoisIdx} moisYear={moisYear}/>
          </div>
        </div>
      </div>
    );
  }

  if(resetMode) return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:"linear-gradient(135deg, #005653 0%, #003d3a 100%)",fontFamily:"'Nunito',sans-serif"}}>
      <div style={{background:"white",borderRadius:20,padding:"48px 40px",width:"100%",maxWidth:420,boxShadow:"0 24px 60px rgba(0,0,0,0.3)"}}>
        <div style={{textAlign:"center",marginBottom:32}}>
          <div style={{fontSize:28,fontWeight:900,color:"#005653"}}>NVM FINANCE</div>
          <div style={{fontSize:13,color:"#6aaca8",marginTop:4,textTransform:"uppercase",letterSpacing:"0.1em"}}>Définir votre mot de passe</div>
        </div>
        <div style={{marginBottom:16}}>
          <label style={{fontSize:11,fontWeight:800,color:"#6aaca8",display:"block",marginBottom:6,textTransform:"uppercase",letterSpacing:"0.08em"}}>Nouveau mot de passe</label>
          <input type="password" value={resetPassword} onChange={e=>setResetPassword(e.target.value)} placeholder="Minimum 8 caractères"
            style={{width:"100%",padding:"12px 16px",borderRadius:10,border:"1.5px solid #a7d4d0",fontSize:14,fontFamily:"'Nunito',sans-serif",outline:"none",boxSizing:"border-box"}}/>
        </div>
        <div style={{marginBottom:24}}>
          <label style={{fontSize:11,fontWeight:800,color:"#6aaca8",display:"block",marginBottom:6,textTransform:"uppercase",letterSpacing:"0.08em"}}>Confirmer le mot de passe</label>
          <input type="password" value={resetConfirm} onChange={e=>setResetConfirm(e.target.value)} placeholder="Répétez votre mot de passe"
            style={{width:"100%",padding:"12px 16px",borderRadius:10,border:"1.5px solid #a7d4d0",fontSize:14,fontFamily:"'Nunito',sans-serif",outline:"none",boxSizing:"border-box"}}/>
        </div>
        {resetMsg&&<div style={{color:resetMsg.includes("✅")?"#059669":"#dc2626",fontSize:13,marginBottom:16,textAlign:"center"}}>{resetMsg}</div>}
        <button onClick={async()=>{
          if(resetPassword.length<8){setResetMsg("Minimum 8 caractères.");return;}
          if(resetPassword!==resetConfirm){setResetMsg("Les mots de passe ne correspondent pas.");return;}
          const {error}=await supabase.auth.updateUser({password:resetPassword});
          if(error){setResetMsg("Erreur: "+error.message);return;}
          setResetMsg("✅ Mot de passe défini ! Connexion en cours...");
          // Mettre à jour first_login et connecter le client
          const {data:sess} = await supabase.auth.getSession();
          if(sess?.session?.user?.email) {
            const userEmail = sess.session.user.email;
            await supabase.from("client_users").update({first_login:false}).eq("email",userEmail);
            // Vérifier si admin ou client
            const {data:adminData} = await supabase.from("admin_users").select("*").eq("email",userEmail).single();
            if(adminData) {
              setTimeout(()=>{ setResetMode(false); setUser({id:"admin",email:userEmail,role:"ADMIN",name:"Administrateur NVM",firstLogin:false}); setView("clients"); },2000);
            } else {
              const {data:clientUser} = await supabase.from("client_users").select("*").eq("email",userEmail).single();
              if(clientUser) {
                setTimeout(()=>{ setResetMode(false); setUser({id:"c"+clientUser.client_id,email:userEmail,role:"CLIENT",clientId:clientUser.client_id,name:"",firstLogin:false}); setView("dashboard"); },2000);
              } else {
                setTimeout(()=>setResetMode(false),2000);
              }
            }
          } else {
            setTimeout(()=>setResetMode(false),2000);
          }
        }} style={{width:"100%",padding:"14px",background:"#005653",color:"white",border:"none",borderRadius:12,fontSize:15,fontWeight:800,cursor:"pointer",fontFamily:"'Nunito',sans-serif"}}>
          Définir mon mot de passe →
        </button>
      </div>
    </div>
  );
  if (!user) return <LoginPage onLogin={handleLogin}/>;

  if (user.role==="CLIENT") {
    const client=clients.find(c=>c.id===user.clientId);
    return (
      <div style={{display:"flex",height:"100vh",fontFamily:"'Nunito',sans-serif"}}>
        <GlobalCSS/>
        {/* Popup première connexion — priorité absolue */}
        {user.firstLogin&&<FirstLoginModal user={user} onComplete={(u)=>setUser(u)}/>}
        <ClientSidebar view={view} setView={setView} onLogout={handleLogout} clientName={client?.name||user.name} alertCount={client?calcAlertes(client,moisIdx,moisYear).filter(a=>a.level==="red"||a.level==="orange").length:0}/>
        <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
          <TopBar title={CLIENT_TITLES[view]||"Dashboard"} user={user}/>
          <div style={{flex:1,overflowY:"auto"}}>
            {client&&<ClientSpace client={client} view={view} moisIdx={moisIdx} setMoisIdx={setMoisIdx} moisYear={moisYear}/>}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={{display:"flex",height:"100vh",fontFamily:"'Nunito',sans-serif"}}>
      <GlobalCSS/>
      {CredentialsModal}
      {FirstLoginPopup}
      <AdminSidebar view={view} setView={setView} onLogout={handleLogout} clientCount={clients.length} alertCount={totalAlerts}/>
      <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        <TopBar title={ADMIN_TITLES[view]||"Admin"} user={user}/>
        <div style={{flex:1,overflowY:"auto"}}>
          {view==="clients"&&<AdminClients clients={clients} onViewAsClient={setPreviewClient} onAddClient={handleAddClient} onUpdateClient={updateClient} onDeleteClient={(id)=>{(async()=>{
          // Récupérer l'email du client avant suppression
          const clientToDelete = clients.find(c=>c.id===id);
          const emailToDelete = clientToDelete?.email || USERS_AUTH.find(u=>u.clientId===id)?.email;
          // Supprimer du state
          setClients(prev=>prev.filter(c=>c.id!==id));
          const idx=USERS_AUTH.findIndex(u=>u.clientId===id);
          if(idx!==-1)USERS_AUTH.splice(idx,1);
          // Supprimer de Supabase
          await supabase.from("clients").delete().eq("id",id);
          await supabase.from("client_users").delete().eq("client_id",id);
          await supabase.from("imports_csv").delete().eq("client_id",id);
          // Supprimer de Supabase Auth
          if(emailToDelete) {
            fetch("/api/delete-user",{
              method:"POST",
              headers:{"Content-Type":"application/json"},
              body:JSON.stringify({email:emailToDelete})
            }).catch(e=>console.error("Erreur suppression Auth:",e));
          }
        })();}}/>}
          {view==="acces"&&<AdminAcces clients={clients}/>}
          {view==="saisie"&&<AdminSaisie clients={clients} onUpdateClient={updateClient}/>}
          {view==="financier"&&<AdminFinancier clients={clients} onUpdateClient={updateClient}/>}
          {view==="alertes"&&<AlertesView clients={clients} moisIdx={moisIdx} moisYear={moisYear}/>}
          {view==="rapports"&&<RapportIA clients={clients} moisIdx={moisIdx} moisYear={moisYear}/>}
        </div>
      </div>
    </div>
  );
}
